import { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../Api';

function Events() {
  const navigate = useNavigate();
  const [events, setEvents] = useState([]);
  const [form, setForm] = useState({
    title: '',
    description: '',
    registration_deadline: '',
    submission_deadline: '',
    max_team_size: 4
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchEvents();
  }, []);

  const fetchEvents = async () => {
    setLoading(true);
    setError('');

    try {
      const res = await api.get('events/');
      setEvents(res.data);
    } catch (err) {
      if (err.response?.status === 401) {
        setError('Please login before viewing events.');
      } else {
        setError('Could not load events.');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    try {
      await api.post('events/', form);
      setForm({
        title: '',
        description: '',
        registration_deadline: '',
        submission_deadline: '',
        max_team_size: 4
      });
      fetchEvents();
    } catch (err) {
      setError('Could not create event. Please check every field.');
    }
  };

  const logout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('refreshToken');
    navigate('/');
  };

  return (
    <main className="app-shell">
      <nav className="topbar">
        <strong>Campus Event Manager</strong>
        <div>
          <Link to="/dashboard">Dashboard</Link>
          <button className="secondary" onClick={logout}>Logout</button>
        </div>
      </nav>

      <section className="page-header">
        <p className="eyebrow">Events</p>
        <h1>Campus Events</h1>
        <p className="muted">Create a new event and track its registration and submission deadlines.</p>
      </section>

      <section className="content-grid">
        <form className="panel" onSubmit={handleSubmit}>
          <h2>Create Event</h2>

          <label>
            Title
            <input
              value={form.title}
              onChange={(e) =>
                setForm({ ...form, title: e.target.value })
              }
            />
          </label>

          <label>
            Description
            <textarea
              value={form.description}
              onChange={(e) =>
                setForm({ ...form, description: e.target.value })
              }
            />
          </label>

          <label>
            Registration Deadline
            <input
              type="datetime-local"
              value={form.registration_deadline}
              onChange={(e) =>
                setForm({ ...form, registration_deadline: e.target.value })
              }
            />
          </label>

          <label>
            Submission Deadline
            <input
              type="datetime-local"
              value={form.submission_deadline}
              onChange={(e) =>
                setForm({ ...form, submission_deadline: e.target.value })
              }
            />
          </label>

          <label>
            Max Team Size
            <input
              type="number"
              min="1"
              value={form.max_team_size}
              onChange={(e) =>
                setForm({ ...form, max_team_size: Number(e.target.value) })
              }
            />
          </label>

          <button>Create Event</button>
        </form>

        <section className="panel">
          <h2>Available Events</h2>
          {loading && <p className="muted">Loading events...</p>}
          {error && <p className="error">{error}</p>}

          {!loading && !error && events.length === 0 && (
            <p className="muted">No events yet. Create the first one.</p>
          )}

          <div className="event-list">
            {events.map((event) => (
              <article className="event-card" key={event.id}>
                <h3>{event.title}</h3>
                <p>{event.description}</p>
                <dl>
                  <div>
                    <dt>Organizer</dt>
                    <dd>{event.organizer_name || 'Unknown'}</dd>
                  </div>
                  <div>
                    <dt>Team Size</dt>
                    <dd>{event.max_team_size}</dd>
                  </div>
                </dl>
              </article>
            ))}
          </div>
        </section>
      </section>
    </main>
  );
}

export default Events;
